package kingdom.smp.client;

import net.minecraft.ChatFormatting;
import net.minecraft.client.Minecraft;
import net.minecraft.client.gui.screens.inventory.AbstractContainerScreen;
import net.minecraft.client.gui.screens.inventory.SmithingScreen;
import net.minecraft.network.chat.Component;
import net.neoforged.bus.api.SubscribeEvent;
import net.neoforged.neoforge.client.event.ScreenEvent;
import org.lwjgl.glfw.GLFW;

/**
 * F4 / Tab / arrow / drag debug overlay for the Ironhold Smithing reskin.
 * Generated by scripts/gen_gui_reskins.py.
 */
public final class SmithingSlotDebugHandler {
    private SmithingSlotDebugHandler() {}

    private static boolean isSmithing(Object screen) {
        return screen instanceof SmithingScreen;
    }

    @SubscribeEvent
    public static void onKey(ScreenEvent.KeyPressed.Pre event) {
        if (!isSmithing(event.getScreen())) return;
        int key = event.getKeyEvent().key();
        boolean shift = (event.getKeyEvent().modifiers() & GLFW.GLFW_MOD_SHIFT) != 0;

        if (key == GLFW.GLFW_KEY_F4) {
            SmithingSlotDebug.toggleEditMode();
            chat("§b[ironhold/smithing] edit mode " + (SmithingSlotDebug.isEditMode() ? "ON" : "OFF"));
            event.setCanceled(true);
            return;
        }
        if (!SmithingSlotDebug.isEditMode()) return;
        int step = shift ? 5 : 1;
        switch (key) {
            case GLFW.GLFW_KEY_TAB -> { SmithingSlotDebug.cycleSelection(shift ? -1 : 1); chat(SmithingSlotDebug.summary()); }
            case GLFW.GLFW_KEY_LEFT  -> { SmithingSlotDebug.nudge(-step, 0); chat(SmithingSlotDebug.summary()); }
            case GLFW.GLFW_KEY_RIGHT -> { SmithingSlotDebug.nudge( step, 0); chat(SmithingSlotDebug.summary()); }
            case GLFW.GLFW_KEY_UP    -> { SmithingSlotDebug.nudge(0, -step); chat(SmithingSlotDebug.summary()); }
            case GLFW.GLFW_KEY_DOWN  -> { SmithingSlotDebug.nudge(0,  step); chat(SmithingSlotDebug.summary()); }
            case GLFW.GLFW_KEY_P -> {
                String dump = SmithingSlotDebug.printJava();
                System.out.println(dump);
                for (String line : dump.split("\n")) chat(line);
            }
            case GLFW.GLFW_KEY_R -> { SmithingSlotDebug.resetAll(); chat("§e[ironhold/smithing] reset to defaults"); }
            default -> { return; }
        }
        event.setCanceled(true);
    }

    @SubscribeEvent
    public static void onMouseDown(ScreenEvent.MouseButtonPressed.Pre event) {
        if (!isSmithing(event.getScreen())) return;
        if (!SmithingSlotDebug.isEditMode()) return;
        if (event.getMouseButtonEvent().button() != 0) return;
        AbstractContainerScreen<?> s = (AbstractContainerScreen<?>) event.getScreen();
        int mx = (int) event.getMouseX();
        int my = (int) event.getMouseY();
        if (SmithingSlotDebug.tryStartDrag(mx, my, s.getGuiLeft(), s.getGuiTop())) {
            event.setCanceled(true);
        }
    }

    @SubscribeEvent
    public static void onMouseDrag(ScreenEvent.MouseDragged.Pre event) {
        if (!isSmithing(event.getScreen())) return;
        if (!SmithingSlotDebug.isDragging()) return;
        AbstractContainerScreen<?> s = (AbstractContainerScreen<?>) event.getScreen();
        int mx = (int) event.getMouseX();
        int my = (int) event.getMouseY();
        SmithingSlotDebug.updateDrag(mx, my, s.getGuiLeft(), s.getGuiTop());
        event.setCanceled(true);
    }

    @SubscribeEvent
    public static void onMouseUp(ScreenEvent.MouseButtonReleased.Pre event) {
        if (!isSmithing(event.getScreen())) return;
        if (!SmithingSlotDebug.isDragging()) return;
        SmithingSlotDebug.endDrag();
        chat(SmithingSlotDebug.summary());
        event.setCanceled(true);
    }

    private static void chat(String msg) {
        Minecraft mc = Minecraft.getInstance();
        if (mc.player != null) mc.player.sendSystemMessage(Component.literal(msg).withStyle(ChatFormatting.AQUA));
    }
}
